WITH filtered AS ( SELECT id, stock_code, title, title_zh, link, pub_date_gmt, pub_date_bj, tags FROM us_stock_rss WHERE pub_date_gmt >= #{startTime} AND pub_date_gmt <= #{endTime}
AND (title IS NULL OR title NOT LIKE CONCAT('%', #{kw}, '%')) AND (title_zh IS NULL OR title_zh NOT LIKE CONCAT('%', #{kw}, '%'))
), ranked AS ( SELECT filtered.*, COUNT(*) OVER (PARTITION BY stock_code) AS frequency, ROW_NUMBER() OVER (PARTITION BY stock_code ORDER BY pub_date_gmt DESC, id DESC) AS rn FROM filtered ) SELECT id, stock_code, title, title_zh, link, pub_date_gmt, pub_date_bj, tags, frequency FROM ranked WHERE rn = 1 AND frequency >= #{threshold} ORDER BY frequency DESC, pub_date_gmt DESC LIMIT #{limit}

SELECT id, stock_code, title, title_zh, link, pub_date_gmt, pub_date_bj, tags FROM us_stock_rss WHERE stock_code IN
#{stockCode}
AND pub_date_gmt >= #{startTime} AND pub_date_gmt <= #{endTime}
AND (title IS NULL OR title NOT LIKE CONCAT('%', #{kw}, '%')) AND (title_zh IS NULL OR title_zh NOT LIKE CONCAT('%', #{kw}, '%'))
ORDER BY stock_code ASC, pub_date_gmt DESC
